selector_to_html = {"a[href=\"#scan-phase-correction\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Scan-Phase Correction<a class=\"headerlink\" href=\"#scan-phase-correction\" title=\"Link to this heading\">#</a></h3><p>Preview bidirectional phase correction before saving.</p>", "a[href=\"#load-options\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Load Options<a class=\"headerlink\" href=\"#load-options\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#suite2p-processing\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Suite2p Processing<a class=\"headerlink\" href=\"#suite2p-processing\" title=\"Link to this heading\">#</a></h2><p>Access via <strong>Process</strong> tab.</p>", "a[href=\"#spatial-crop\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Spatial Crop<a class=\"headerlink\" href=\"#spatial-crop\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#python-api\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Python API<a class=\"headerlink\" href=\"#python-api\" title=\"Link to this heading\">#</a></h2><p>If no input provided and Qt available, opens file dialog.</p>", "a[href=\"#window-functions\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Window Functions<a class=\"headerlink\" href=\"#window-functions\" title=\"Link to this heading\">#</a></h3><p><strong>Parameters:</strong></p>", "a[href=\"#output-formats\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Output Formats<a class=\"headerlink\" href=\"#output-formats\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#summary-stats\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Summary Stats<a class=\"headerlink\" href=\"#summary-stats\" title=\"Link to this heading\">#</a></h3><p>Per z-plane statistics (computed on every 10th frame):</p>", "a[href=\"#data-selection-dialog\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Data Selection Dialog<a class=\"headerlink\" href=\"#data-selection-dialog\" title=\"Link to this heading\">#</a></h2><h3>Open File vs Select Folder<a class=\"headerlink\" href=\"#open-file-vs-select-folder\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#saving-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Saving Data<a class=\"headerlink\" href=\"#saving-data\" title=\"Link to this heading\">#</a></h2><p>Access via <strong>File \u2192 Save As</strong> or <strong>Process</strong> tab.</p>", "a[href=\"#gui-user-guide\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">GUI User Guide<a class=\"headerlink\" href=\"#gui-user-guide\" title=\"Link to this heading\">#</a></h1><p>Interactive data preview and processing tools for calcium imaging data.</p>", "a[href=\"#quick-start\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Quick Start<a class=\"headerlink\" href=\"#quick-start\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#open-file-vs-select-folder\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Open File vs Select Folder<a class=\"headerlink\" href=\"#open-file-vs-select-folder\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#preview-widget\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Preview Widget<a class=\"headerlink\" href=\"#preview-widget\" title=\"Link to this heading\">#</a></h2><h3>Window Functions<a class=\"headerlink\" href=\"#window-functions\" title=\"Link to this heading\">#</a></h3><p><strong>Parameters:</strong></p>", "a[href=\"#save-options\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Save Options<a class=\"headerlink\" href=\"#save-options\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#supported-formats\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Supported Formats<a class=\"headerlink\" href=\"#supported-formats\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#features\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Features<a class=\"headerlink\" href=\"#features\" title=\"Link to this heading\">#</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
